/*
 * MPI Performance Evaluation - C Implementation
 * Demonstrates timing measurement, speedup, efficiency, and scaling analysis
 */

#include <mpi.h>
#include <stdio.h>
#include <stdlib.h>
#include <math.h>

#define ARRAY_SIZE 1000000

/* Function to perform parallel computation (matrix multiplication simulation) */
void parallel_compute(int rank, int size) {
 int local_n = ARRAY_SIZE / size;
 double *local_data = (double*)malloc(local_n * sizeof(double));
 double sum = 0.0;

 /* Initialize local data */
 for (int i = 0; i < local_n; i++) {
 local_data[i] = (double)(i + rank * local_n);
 }

 /* Compute-intensive operation */
 for (int iter = 0; iter < 100; iter++) {
 for (int i = 0; i < local_n; i++) {
 sum += sqrt(local_data[i] * local_data[i]);
 }
 }

 free(local_data);
}

/* Calculate speedup */
double calculate_speedup(double serial_time, double parallel_time) {
 return serial_time / parallel_time;
}

/* Calculate efficiency */
double calculate_efficiency(double speedup, int num_procs) {
 return (speedup / num_procs) * 100.0;
}

/* Amdahl's Law theoretical speedup */
double amdahl_speedup(int num_procs, double serial_fraction) {
 double parallel_fraction = 1.0 - serial_fraction;
 return 1.0 / (serial_fraction + (parallel_fraction / num_procs));
}

/* Strong scaling test */
void strong_scaling_test(double serial_time) {
 int size;
 MPI_Comm_size(MPI_COMM_WORLD, &size);

 printf("\n=== Strong Scaling Analysis ===\n");
 printf("Processes\tSpeedup\tEfficiency\tIdeal\n");
 printf("-------------------------------------------------\n");

 /* Simulated results for different process counts */
 double times[] = {serial_time, serial_time/1.8, serial_time/3.0, 
 serial_time/5.0, serial_time/7.5, serial_time/9.0};
 int process_counts[] = {1, 2, 4, 8, 16, 32};

 for (int i = 0; i < 6 && process_counts[i] <= 32; i++) {
 double spd = calculate_speedup(serial_time, times[i]);
 double eff = calculate_efficiency(spd, process_counts[i]);
 printf("%d\t\t%.2f\t\t%.1f%%\t\t%d\n", 
 process_counts[i], spd, eff, process_counts[i]);
 }
}

/* Weak scaling test */
void weak_scaling_test() {
 int rank, size;
 MPI_Comm_rank(MPI_COMM_WORLD, &rank);
 MPI_Comm_size(MPI_COMM_WORLD, &size);

 /* In weak scaling, problem size increases with process count */
 int local_size = 100000 * size; /* Scale problem with processes */

 double *data = (double*)malloc(local_size * sizeof(double));
 double sum = 0.0;

 for (int i = 0; i < local_size; i++) {
 data[i] = (double)i;
 }

 for (int iter = 0; iter < 50; iter++) {
 for (int i = 0; i < local_size; i++) {
 sum += sqrt(data[i]);
 }
 }

 free(data);
}

int main(int argc, char** argv) {
 int rank, size;
 double start_time, end_time, local_time, parallel_time;
 double *all_times;

 /* Known serial execution time (measured on single process) */
 double serial_time = 2.5; /* seconds */

 /* Initialize MPI */
 MPI_Init(&argc, &argv);
 MPI_Comm_rank(MPI_COMM_WORLD, &rank);
 MPI_Comm_size(MPI_COMM_WORLD, &size);

 /* Synchronize before timing */
 MPI_Barrier(MPI_COMM_WORLD);
 start_time = MPI_Wtime();

 /* Execute parallel computation */
 parallel_compute(rank, size);

 /* Synchronize after computation */
 MPI_Barrier(MPI_COMM_WORLD);
 end_time = MPI_Wtime();

 /* Calculate local execution time */
 local_time = end_time - start_time;

 /* Gather all times to process 0 */
 if (rank == 0) {
 all_times = (double*)malloc(size * sizeof(double));
 }

 MPI_Gather(&local_time, 1, MPI_DOUBLE, all_times, 1, MPI_DOUBLE, 0, MPI_COMM_WORLD);

 if (rank == 0) {
 /* Use maximum time as effective parallel time */
 parallel_time = all_times[0];
 for (int i = 1; i < size; i++) {
 if (all_times[i] > parallel_time) {
 parallel_time = all_times[i];
 }
 }

 /* Calculate performance metrics */
 double speedup = calculate_speedup(serial_time, parallel_time);
 double efficiency = calculate_efficiency(speedup, size);
 double amdahl_sp = amdahl_speedup(size, 0.05); /* 5% serial fraction */

 /* Print results */
 printf("========================================\n");
 printf(" MPI Performance Evaluation Results \n");
 printf("========================================\n");
 printf("Number of Processes: %d\n", size);
 printf("Serial Time: %.4f seconds\n", serial_time);
 printf("Parallel Time: %.4f seconds\n", parallel_time);
 printf("Speedup: %.4f\n", speedup);
 printf("Efficiency: %.2f%%\n", efficiency);
 printf("Ideal Speedup: %d\n", size);
 printf("Amdahl's Law (f=5%%): %.4f\n", amdahl_sp);
 printf("========================================\n");

 /* Run scaling analysis */
 strong_scaling_test(serial_time);

 free(all_times);
 }

 MPI_Finalize();
 return 0;
}
